import json
import math
import os
import struct
import sys
from collections import Counter

EPS = 1e-10
ROUND_DP = 6


def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _mag(v):
    return math.sqrt(_dot(v, v))


def _normalize(v):
    m = _mag(v)
    if m < EPS:
        return (0.0, 0.0, 0.0)
    return (v[0] / m, v[1] / m, v[2] / m)


def _triangle_area(v1, v2, v3):
    return 0.5 * _mag(_cross(_sub(v2, v1), _sub(v3, v1)))


def detect_binary(path):
    size = os.path.getsize(path)
    if size < 84:
        return False
    with open(path, 'rb') as f:
        header = f.read(84)
    if len(header) < 84:
        return False
    count = struct.unpack('<I', header[80:84])[0]
    expected = 84 + count * 50
    if expected == size:
        return True
    try:
        with open(path, 'rb') as f:
            prefix = f.read(512)
        prefix.decode('ascii')
        textish = True
    except UnicodeDecodeError:
        textish = False
    if not textish:
        return True
    return False


def parse_binary(path, issues):
    triangles = []
    with open(path, 'rb') as f:
        data = f.read()
    if len(data) < 84:
        issues.append('Binary STL too short')
        return triangles
    count = struct.unpack('<I', data[80:84])[0]
    expected = 84 + count * 50
    if expected != len(data):
        issues.append(f'Binary STL size mismatch: header expects {count} triangle(s)')
        count = max(0, (len(data) - 84) // 50)
    offset = 84
    for i in range(count):
        chunk = data[offset:offset + 50]
        if len(chunk) < 50:
            issues.append(f'Incomplete binary triangle record at index {i}')
            break
        vals = struct.unpack('<12fH', chunk)
        n = (vals[0], vals[1], vals[2])
        v1 = (vals[3], vals[4], vals[5])
        v2 = (vals[6], vals[7], vals[8])
        v3 = (vals[9], vals[10], vals[11])
        triangles.append((n, [v1, v2, v3]))
        offset += 50
    return triangles


def parse_ascii(path, issues):
    triangles = []
    try:
        with open(path, 'r', errors='replace') as fh:
            lines = fh.readlines()
    except Exception as e:
        issues.append(f'Failed to read ASCII STL: {e}')
        return triangles
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f'Malformed facet normal at line {i + 1}')
                i += 1
                continue
            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == 'outer loop':
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith('vertex'):
                            vparts = vline.split()
                            try:
                                vertices.append((float(vparts[1]), float(vparts[2]), float(vparts[3])))
                            except (IndexError, ValueError):
                                issues.append(f'Malformed vertex at line {i + 1}')
                        else:
                            issues.append(f'Expected vertex at line {i + 1}')
                        i += 1
                while i < len(lines) and lines[i].strip() not in ('endloop', 'facet normal'):
                    if lines[i].strip() == 'endfacet':
                        break
                    i += 1
                if i < len(lines) and lines[i].strip() == 'endloop':
                    i += 1
                if i < len(lines) and lines[i].strip() == 'endfacet':
                    i += 1
            else:
                issues.append(f'Missing outer loop near line {i + 1}')
            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f'Incomplete triangle near line {i + 1}')
            continue
        i += 1
    return triangles


def validate(path):
    issues = []
    if not os.path.exists(path):
        return {'valid': False, 'issues': ['File not found']}
    is_binary = detect_binary(path)
    triangles = parse_binary(path, issues) if is_binary else parse_ascii(path, issues)
    if not triangles:
        issues.append('No valid faces found')
        return {'valid': False, 'issues': issues}

    edge_count = Counter()
    degenerate = 0
    inverted = 0
    zero_normals = 0

    for declared_normal, verts in triangles:
        rounded = [tuple(round(c, ROUND_DP) for c in v) for v in verts]
        if len(set(rounded)) < 3 or _triangle_area(*verts) < EPS:
            degenerate += 1
        for j in range(3):
            edge = tuple(sorted((rounded[j], rounded[(j + 1) % 3])))
            edge_count[edge] += 1
        edge1 = _sub(verts[1], verts[0])
        edge2 = _sub(verts[2], verts[0])
        wn = _cross(edge1, edge2)
        if _mag(wn) < EPS:
            continue
        dn = _normalize(declared_normal)
        if _mag(declared_normal) < EPS:
            zero_normals += 1
            continue
        if _dot(dn, _normalize(wn)) < -0.99:
            inverted += 1

    open_edges = sum(1 for c in edge_count.values() if c == 1)
    nonmanifold_edges = sum(1 for c in edge_count.values() if c > 2)

    if degenerate:
        issues.append(f'Mesh has {degenerate} degenerate triangle(s)')
    if open_edges:
        issues.append(f'Mesh has {open_edges} open edge(s) — not a closed solid')
    if nonmanifold_edges:
        issues.append(f'Mesh has {nonmanifold_edges} non-manifold edge(s)')
    if inverted:
        issues.append(f'Mesh has {inverted} face(s) with inverted declared normals relative to winding')
    if zero_normals:
        issues.append(f'Mesh has {zero_normals} face(s) with zero declared normals')

    return {'valid': len(issues) == 0, 'issues': issues}


if __name__ == '__main__':
    if len(sys.argv) != 2:
        print(json.dumps({'valid': False, 'issues': ['usage: stl_validate_cli.py <file.stl>']}))
        sys.exit(1)
    print(json.dumps(validate(sys.argv[1])))

